question.en:
Consider this Next.js 13+ App Router component. What will happen and why?


export default function Page() {
  const [data, setData] = useState(null);

  useEffect(() => {
    fetch('/api/data').then(r => r.json()).then(setData);
  }, []);

  return <div>{data}</div>;
}

